namespace sv_0afdbd8427524a2fa2373fe3fe3f0148.Services;

/// <summary>
/// Immutable record cascaded app-wide via CascadingValueSource so every
/// component — regardless of render mode — can read the current warehouse.
/// </summary>
public record WarehouseInfo(string Id, string Name)
{
    public static readonly WarehouseInfo[] Available =
    [
        new("WH-A", "Warehouse A"),
        new("WH-B", "Warehouse B"),
        new("WH-C", "Warehouse C"),
    ];

    public static WarehouseInfo Default => Available[0];
}

namespace sv_0afdbd8427524a2fa2373fe3fe3f0148.Services;

/// <summary>
/// Scoped service that polls for low-stock alerts and notifies all
/// subscribed components via the <see cref="OnChange"/> event.
/// Scoped lifetime ensures each circuit (user) gets its own instance.
/// </summary>
public sealed class InventoryAlertService : IDisposable
{
    private readonly Random _random = new();
    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;
    private int _subscriberCount;

    public int LowStockCount { get; private set; }

    /// <summary>
    /// Fired whenever new alert data arrives.  Subscribers MUST wrap
    /// StateHasChanged in InvokeAsync because this fires from a timer thread.
    /// </summary>
    public event Action? OnChange;

    /// <summary>Simulates a database query returning low-stock item count.</summary>
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        return Task.FromResult(_random.Next(0, 16));
    }

    /// <summary>
    /// Begin polling every 10 seconds for the given warehouse.
    /// Reference-counted: multiple components can call StartPolling and
    /// polling only truly stops when all have called StopPolling.
    /// </summary>
    public void StartPolling(string warehouseId)
    {
        _subscriberCount++;

        if (_timer is not null)
            return; // already running

        _cts = new CancellationTokenSource();
        _timer = new PeriodicTimer(TimeSpan.FromSeconds(10));

        _ = PollLoopAsync(warehouseId, _cts.Token);
    }

    /// <summary>Stop polling when the last subscriber leaves.</summary>
    public void StopPolling()
    {
        _subscriberCount = Math.Max(0, _subscriberCount - 1);

        if (_subscriberCount == 0)
        {
            StopTimer();
        }
    }

    /// <summary>
    /// Restart polling for a different warehouse (e.g. after warehouse switch).
    /// Preserves the subscriber count.
    /// </summary>
    public void RestartPolling(string warehouseId)
    {
        if (_subscriberCount <= 0)
            return;

        StopTimer();

        _cts = new CancellationTokenSource();
        _timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
        _ = PollLoopAsync(warehouseId, _cts.Token);
    }

    private async Task PollLoopAsync(string warehouseId, CancellationToken ct)
    {
        // Fetch immediately on start so the UI doesn't wait 10 s for first data.
        await FetchAndNotifyAsync(warehouseId);

        while (!ct.IsCancellationRequested)
        {
            try
            {
                if (!await _timer!.WaitForNextTickAsync(ct))
                    break;
            }
            catch (OperationCanceledException)
            {
                break;
            }

            await FetchAndNotifyAsync(warehouseId);
        }
    }

    private async Task FetchAndNotifyAsync(string warehouseId)
    {
        LowStockCount = await GetLowStockCountAsync(warehouseId);
        OnChange?.Invoke();
    }

    private void StopTimer()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
        _timer?.Dispose();
        _timer = null;
    }

    public void Dispose() => StopTimer();
}

