using Microsoft.AspNetCore.Components;
using sv_0afdbd8427524a2fa2373fe3fe3f0148.Components;
using sv_0afdbd8427524a2fa2373fe3fe3f0148.Services;

var builder = WebApplication.CreateBuilder(args);

// Add services to the container.
builder.Services.AddRazorComponents()
    .AddInteractiveServerComponents();

// Warehouse selection — cascaded via DI so it crosses render-mode boundaries.
// Each circuit (user) gets its own CascadingValueSource (scoped).
builder.Services.AddCascadingValue(sp =>
    new CascadingValueSource<WarehouseInfo>(WarehouseInfo.Default, isFixed: false));

// Inventory alert service — scoped so each user has independent polling/counts.
builder.Services.AddScoped<InventoryAlertService>();

