@* Interactive warehouse dropdown rendered inside the static layout. *@
@rendermode InteractiveServer

@inject CascadingValueSource<WarehouseInfo> WarehouseSource
@inject InventoryAlertService AlertService
@using sv_0afdbd8427524a2fa2373fe3fe3f0148.Services

<select class="form-select form-select-sm w-auto"
        value="@_selectedId"
        @onchange="OnWarehouseChanged">
    @foreach (var wh in WarehouseInfo.Available)
    {
        <option value="@wh.Id">@wh.Name</option>
    }
</select>

@code {
    private string _selectedId = WarehouseInfo.Default.Id;

    private async Task OnWarehouseChanged(ChangeEventArgs e)
    {
        _selectedId = e.Value?.ToString() ?? WarehouseInfo.Default.Id;
        var warehouse = WarehouseInfo.Available.First(w => w.Id == _selectedId);

        // Push to all [CascadingParameter] subscribers across render modes.
        await WarehouseSource.NotifyChangedAsync(warehouse);

        // Restart polling for the new warehouse so alert counts update.
        AlertService.RestartPolling(warehouse.Id);
    }
}

@* Low-stock alert badge.  Subscribes to InventoryAlertService.OnChange
   so it refreshes whenever ANY component triggers a poll update. *@
@rendermode InteractiveServer

@inject InventoryAlertService AlertService
@implements IDisposable

@if (AlertService.LowStockCount > 0)
{
    <span class="badge bg-danger rounded-pill ms-1">@AlertService.LowStockCount</span>
}
else
{
    <span class="badge bg-success rounded-pill ms-1">0</span>
}

@code {
    private Action? _handler;

    protected override void OnInitialized()
    {
        // Wrap in InvokeAsync because OnChange fires from a timer thread.
        _handler = () => InvokeAsync(StateHasChanged);
        AlertService.OnChange += _handler;
    }

    public void Dispose()
    {
        AlertService.OnChange -= _handler;
    }
}

