@* Low-stock alert badge.  Subscribes to InventoryAlertService.OnChange
   so it refreshes whenever ANY component triggers a poll update. *@
@rendermode InteractiveServer

@inject InventoryAlertService AlertService
@implements IDisposable

@if (AlertService.LowStockCount > 0)
{
    <span class="badge bg-danger rounded-pill ms-1">@AlertService.LowStockCount</span>
}
else
{
    <span class="badge bg-success rounded-pill ms-1">0</span>
}

@code {
    private Action? _handler;

    protected override void OnInitialized()
    {
        // Wrap in InvokeAsync because OnChange fires from a timer thread.
        _handler = () => InvokeAsync(StateHasChanged);
        AlertService.OnChange += _handler;
    }

    public void Dispose()
    {
        AlertService.OnChange -= _handler;
    }
}

