@page "/dashboard"
@rendermode InteractiveServer

@inject InventoryAlertService AlertService
@using sv_0afdbd8427524a2fa2373fe3fe3f0148.Services
@implements IDisposable

<PageTitle>Warehouse Dashboard</PageTitle>

<h1>Warehouse Dashboard</h1>

<div class="row mt-4">
    <div class="col-md-4">
        <div class="card">
            <div class="card-body text-center">
                <h5 class="card-title">Current Warehouse</h5>
                <p class="card-text fs-4">@(Warehouse?.Name ?? "Loading…")</p>
                <p class="text-muted">@(Warehouse?.Id)</p>
            </div>
        </div>
    </div>

    <div class="col-md-4">
        <div class="card">
            <div class="card-body text-center">
                <h5 class="card-title">Low-Stock Alerts</h5>
                <p class="card-text fs-1">
                    <AlertBadge />
                </p>
                <p class="text-muted">Polling every 10 s</p>
            </div>
        </div>
    </div>

    <div class="col-md-4">
        <div class="card">
            <div class="card-body text-center">
                <h5 class="card-title">Status</h5>
                <p class="card-text">
                    @if (AlertService.LowStockCount == 0)
                    {
                        <span class="text-success fw-bold">All Clear ✓</span>
                    }
                    else if (AlertService.LowStockCount > 10)
                    {
                        <span class="text-danger fw-bold">Critical ⚠</span>
                    }
                    else
                    {
                        <span class="text-warning fw-bold">Review Needed</span>
                    }
                </p>
            </div>
        </div>
    </div>
</div>

@code {
    [CascadingParameter]
    private WarehouseInfo? Warehouse { get; set; }

    private Action? _handler;

    protected override void OnInitialized()
    {
        _handler = () => InvokeAsync(StateHasChanged);
        AlertService.OnChange += _handler;

        // Start polling for the current warehouse.
        AlertService.StartPolling(Warehouse?.Id ?? WarehouseInfo.Default.Id);
    }

    public void Dispose()
    {
        AlertService.OnChange -= _handler;
        AlertService.StopPolling();
    }
}

